 elif pd.kind == DivergenceKind.RA_INTRINSIC:
 tag = "DIVERGENCE (intrinsic)"
 elif pd.kind == DivergenceKind.RA_INPUT_DERIVED:
 tag = "DIVERGENCE (input-derived)"
 else:
