 for v in views if v.ig_idx >= 0
 )
 if earlier_unmapped:
 fact = _replace_fact(fact, earlier_unmapped_warning=True)
 return FirstDivergenceReport(fact=fact, source=None)


def _replace_fact(fact: AllocatorFact, **changes) -> AllocatorFact:
